function onLoad() {

	var state = (g_form.isNewRecord()) ? "New" : g_form.getValue("state");

	if (state == "New"){
		setOwnerEnableInstructions();
	}else {
		//KT - STRY0063639 - Mar-16-2020
		setInstructionsUpdateState();
	}

	function setInstructionsUpdateState(){
		/*
		Complete, Cancelled:
		Others: Read-only
 		*/
		if (state == "3" || state == "4" || state == "7"){
			g_form.setReadOnly('instructions', true);
		} else {
			/*
			State: Unassigned, Assigned, Accepted, Work in Progress, Reject for Prim Assign, Rejected Assignment, In Review, Rework:
			Task Owner: Edit
			Others: Read-only
 			*/
			var currentUser = g_user.userID;
			var taskOwnerId = g_form.getValue('u_task_requester');

			if (currentUser == taskOwnerId)
				g_form.setReadOnly('instructions', false);
			else
				g_form.setReadOnly('instructions', true);
		}
	}

	function setOwnerEnableInstructions(){
		//HT - STRY0048914
		//KT - STRY0058367 (Mo)
		var isSubTask = g_form.getValue("parent") != undefined && g_form.getValue("parent") != "";
		var currentUser = g_user.userID;

		//Is TopTask, this is not a subtask
		if(!isSubTask){
			var taskOwner = g_form.getValue('u_task_requester');

			if((taskOwner  == currentUser)){
				//if the current user is the task owner set to editable
				g_form.setReadOnly('instructions', false);
			}else{
				//if the current user is not the task owner set to read only
				g_form.setReadOnly('instructions', true);
			}

		}else{
			// IsSubTask
			setSubTaskOwner();
			enableSubTaskInstructions();
		}
	}

	function enableSubTaskInstructions(){
		//KT - STRY0048914
		// IsSubTask
		var parent_sys_id = g_form.getValue('parent');

		var ajax = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'checkUserIsAssignedMemberORTaskOwner');
		ajax.addParam('sysparm_parent', parent_sys_id);
		ajax.getXML(getresponse);

		function getresponse(response){

			var UserIsAssignedMemberORTaskOwner = response.responseXML.documentElement.getAttribute('answer');

			if (UserIsAssignedMemberORTaskOwner)
				g_form.setReadOnly('instructions', false);
			else
				g_form.setReadOnly('instructions', true);
		}
	}

	function setSubTaskOwner(){

		var parent_sys_id = g_form.getValue('parent');

		var ajax = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'setSubTaskTaskOwner');
		ajax.addParam('sysparm_parent', parent_sys_id);
		ajax.getXML(function(response){
			try{
				var subTaskTaskOwner = response.responseXML.documentElement.getAttribute('answer');
				g_form.setValue('u_task_requester', subTaskTaskOwner);

			} catch(e) {
				jslog(e);
			}
		});
	}






